function isRecent(dateStr) {
  if (!dateStr) return true;
  const cleanDate = dateStr.replace(/[\s\.\u00a0]+/g, '-').replace(/-$/, '');
  const d = new Date(cleanDate);
  if (isNaN(d.getTime())) return true;
  const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 365);
  return d >= cutoff;
}

async function findDeptRss(dept) {
  const baseUrl = deptUrlMap[dept]; if (!baseUrl) return null;
  try {
    const html = String(await httpRequest({ method:'GET', url: baseUrl, headers:{'User-Agent':'Mozilla/5.0'} }));
    let m = html.match(/\/bbs\/([\w\d]+)\/(\d+)\//);
    if (!m) return null;
    const rssUrl = baseUrl.replace(/\/index\.do$/, '').replace(/\/$/, '') + '/bbs/' + m[1] + '/' + m[2] + '/rssList.do?row=20';
    return { url: rssUrl, dept, baseUrl };
  } catch(e) { return null; }
}

function parseRss(xml, dept, baseUrl) {
  const items = []; const re = /<item>([\s\S]*?)<\/item>/g; let m;
  while ((m = re.exec(xml)) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*><!\[CDATA\[([\s\S]*?)\]\]>/) || b.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [])[1] || '';
    const rawLink = (b.match(/<link[^>]*>([\s\S]*?)<\/link>/) || b.match(/<guid[^>]*>([\s\S]*?)<\/guid>/) || [])[1] || '';
    const pubDate = (b.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/) || [])[1] || '';
    let link = rawLink.trim();
    if (link && !link.startsWith('http')) link = baseUrl.replace(/\/$/, '') + (link.startsWith('/') ? '' : '/') + link;
    if (title.trim() && isRecent(pubDate)) items.push({ title:title.trim(), date:pubDate, url:link, source:'학과공지(' + dept + ')' });
  }
  return items;
}

