// ── 날짜 추출 ───────────────────────────────────────────────
const Y = new Date().getFullYear();

function pad(n) { return String(n).padStart(2, '0'); }

function parseDateParts(str) {
  // "M. D" or "M.D" or "M/D"
  const m = str.match(/(\d{1,2})[./\s]+(\d{1,2})/);
  if (m) return { mo: pad(m[1]), d: pad(m[2]) };
  return null;
}

function extractFromTitle(title) {
  // Range: (M. D ~ M. D) or M.D~M.D with optional year/요일
  const rng = title.match(/(\d{1,2})[.\s]+(\d{1,2})[^~\d]*~[^~\d]*(\d{1,2})[.\s]+(\d{1,2})/);
  if (rng) {
    const s = `${pad(rng[1])}/${pad(rng[2])}`;
    const e = `${pad(rng[3])}/${pad(rng[4])}`;
    return { label: `${s} ~ ${e}`, startDate: `${Y}-${pad(rng[1])}-${pad(rng[2])}`, endDate: `${Y}-${pad(rng[3])}-${pad(rng[4])}` };
  }
  // Deadline: ~M/D or ~M.D
  const dl = title.match(/~\s*(\d{1,2})[./](\d{1,2})/);
  if (dl) {
    return { label: `~ ${pad(dl[1])}/${pad(dl[2])}`, endDate: `${Y}-${pad(dl[1])}-${pad(dl[2])}` };
  }
  // Single full date: 2026. M. D
  const full = title.match(/20\d{2}[.\s]+(\d{1,2})[.\s]+(\d{1,2})/);
  if (full) {
    return { label: `${full[1]}/${full[2]}`, endDate: `${Y}-${pad(full[1])}-${pad(full[2])}` };
  }
  // M월 D일
  const kor = title.match(/(\d{1,2})월\s*(\d{1,2})일/);
  if (kor) {
    return { label: `${kor[1]}/${kor[2]}`, endDate: `${Y}-${pad(kor[1])}-${pad(kor[2])}` };
  }
  return null;
}

function extractFromContent(html) {
  // Remove tags
  const text = html.replace(/<[^>]+>/g, ' ').replace(/&[a-z]+;/g, ' ');
  // Find best date range: look for range patterns with context keywords
  const patterns = [
    /(?:신청|접수|제출|마감|기간)[^0-9]{0,20}(\d{1,2})[.\s]+(\d{1,2})[^~\d]{0,15}~[^~\d]{0,10}(\d{1,2})[.\s]+(\d{1,2})/,
    /(\d{1,2})[.\s]+(\d{1,2})[^~\d]{0,5}~[^~\d]{0,5}(\d{1,2})[.\s]+(\d{1,2})/,
  ];
  for (const pat of patterns) {
    const m = text.match(pat);
    if (m) {
      const si = pat.source.startsWith('(?:') ? 1 : 0;
      const [, a, b, c, d] = m.slice(si > 0 ? 0 : 0);
      // extract last 4 capture groups
      const caps = m.slice(m.length - 4);
      if (caps[0] && caps[1] && caps[2] && caps[3]) {
        const s = `${pad(caps[0])}/${pad(caps[1])}`;
        const e = `${pad(caps[2])}/${pad(caps[3])}`;
        return { label: `${s} ~ ${e}`, startDate: `${Y}-${pad(caps[0])}-${pad(caps[1])}`, endDate: `${Y}-${pad(caps[2])}-${pad(caps[3])}` };
      }
    }
  }
  // Deadline only
  const dl = text.match(/(?:마감|까지)[^0-9]{0,10}(\d{1,2})[./](\d{1,2})/);
  if (dl) return { label: `~ ${pad(dl[1])}/${pad(dl[2])}`, endDate: `${Y}-${pad(dl[1])}-${pad(dl[2])}` };
  return null;
}

// 1단계: 제목에서 추출
for (const item of items) {
  const extracted = extractFromTitle(item.title || '');
  if (extracted) {
    item.dateRange = extracted.label;
    if (extracted.startDate) item.startDate = extracted.startDate;
    if (extracted.endDate) item.endDate = extracted.endDate;
  }
}

// 2단계: 학교공지 중 미추출 항목 본문 fetch (최대 8개 병렬)
const toFetch = items.filter(i => i.source === '학교공지' && !i.dateRange && i.url).slice(0, 8);
if (toFetch.length > 0) {
  const results = await Promise.all(toFetch.map(async item => {
    try {
      const html = String(await httpRequest({ method: 'GET', url: item.url, headers: { 'User-Agent': 'Mozilla/5.0' } }));
      return { item, result: extractFromContent(html) };
    } catch(e) { return { item, result: null }; }
  }));
  for (const { item, result } of results) {
    if (result) {
      item.dateRange = result.label;
      if (result.startDate) item.startDate = result.startDate;
      if (result.endDate) item.endDate = result.endDate;
    }
  }
}

// ── AI 텍스트 구성 ──────────────────────────────────────────
const webhookBody = $('Webhook [공지]').first().json.body || $('Webhook [공지]').first().json;
const major = webhookBody.major || '';
const careerGoal = webhookBody.career_goal || '';
