const content = $input.first().json.choices[0].message.content;
let parsed;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch[0]);
} catch(e) { return [{ json: { error: '파싱 실패', raw: content } }]; }

const { semester, days, startTime, endTime, classroom, weeks } = parsed;
const year = 2026;
const startMonth = semester === 1 ? 2 : 8; 
const firstDay = new Date(year, startMonth, 1);
let daysUntilMonday = (1 - firstDay.getDay() + 7) % 7;
const semesterStart = new Date(year, startMonth, 1 + daysUntilMonday);

// 2026-03-02가 월요일이며, dayMap은 월(0) ~ 일(6) 오프셋을 가짐
const dayMap = { '월': 0, '화': 1, '수': 2, '목': 3, '금': 4, '토': 5, '일': 6 };

const events = weeks.flatMap(week => {
  const weekIndex = Math.max(0, week.week - 1);
  return days.map(day => {
    const dayOffset = dayMap[day];
    if (dayOffset === undefined) return null;
    const eventDate = new Date(semesterStart);
    eventDate.setDate(semesterStart.getDate() + (weekIndex * 7) + dayOffset);
    const y = eventDate.getFullYear();
    const mo = String(eventDate.getMonth() + 1).padStart(2, '0');
    const d = String(eventDate.getDate()).padStart(2, '0');
    const dateStr = `${y}-${mo}-${d}`;
    return {
      json: {
        title: `[${week.week}주차] ${week.title}`,
        description: `강의방법: ${week.method || ''}\n강의실: ${classroom}`,
        startDateTime: `${dateStr}T${startTime}:00+09:00`,
        endDateTime: `${dateStr}T${endTime}:00+09:00`,
        date: dateStr
      }
    };
  }).filter(Boolean);
});
return events;

